import{_ as a,a as t,b as n}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as i,o as l,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Een Cloudflare R2-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/cloudflare-r2.md","filePath":"nl-NL/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),r={name:"nl-NL/upload/cloudflare-r2.md"};function c(p,e,h,s,b,u){return l(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="een-cloudflare-r2-kanaal-toevoegen" tabindex="-1">Een Cloudflare R2-kanaal toevoegen <a class="header-anchor" href="#een-cloudflare-r2-kanaal-toevoegen" aria-label="Permalink to &quot;Een Cloudflare R2-kanaal toevoegen&quot;">​</a></h1><h2 id="wanneer-dit-geschikt-is" tabindex="-1">Wanneer dit geschikt is <a class="header-anchor" href="#wanneer-dit-geschikt-is" aria-label="Permalink to &quot;Wanneer dit geschikt is&quot;">​</a></h2><p>Gebruik Cloudflare R2 wanneer:</p><ul><li>je ImgBed-site al op Cloudflare draait en je bestanden wilt opslaan in een R2-bucket binnen hetzelfde Cloudflare-account.</li><li>je geen losse S3-endpoint, access key en secret key wilt configureren.</li><li>lezen en schrijven via de R2-binding van Worker of Pages moet lopen met zo weinig mogelijk instellingen.</li></ul><p>Kort gezegd:</p><p>Het R2-kanaal maak je niet handmatig aan in het ImgBed-beheer. Je koppelt eerst een R2-bucket aan het Cloudflare-project. De naam van de bindingvariabele moet exact <code>img_r2</code> zijn.</p><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><ul><li>Een Cloudflare-account.</li><li>Een bestaande R2-bucket.</li><li>Rechten om het Cloudflare-project te beheren waarop ImgBed is gedeployed.</li></ul><h2 id="instellen-in-cloudflare" tabindex="-1">Instellen in Cloudflare <a class="header-anchor" href="#instellen-in-cloudflare" aria-label="Permalink to &quot;Instellen in Cloudflare&quot;">​</a></h2><h3 id="_1-maak-een-r2-bucket" tabindex="-1">1. Maak een R2-bucket <a class="header-anchor" href="#_1-maak-een-r2-bucket" aria-label="Permalink to &quot;1. Maak een R2-bucket&quot;">​</a></h3><ol><li>Log in op het Cloudflare Dashboard.</li><li>Open <code>R2 Object Storage</code>.</li><li>Klik op Create bucket.</li><li>Kies een bucketnaam, bijvoorbeeld <code>imgbed</code>.</li></ol><p>In deze bucket worden de geuploade bestanden opgeslagen.</p><p><img src="'+a+'" alt="R2-bucket maken" loading="lazy"></p><h3 id="_2-koppel-de-bucket-aan-het-imgbed-project" tabindex="-1">2. Koppel de bucket aan het ImgBed-project <a class="header-anchor" href="#_2-koppel-de-bucket-aan-het-imgbed-project" aria-label="Permalink to &quot;2. Koppel de bucket aan het ImgBed-project&quot;">​</a></h3><p>Kies de bindinglocatie op basis van je deploymenttype:</p><table tabindex="0"><thead><tr><th>Deploymenttype</th><th>Bindinglocatie</th></tr></thead><tbody><tr><td>Pages</td><td>Huidig Pages-project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Huidige Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>Bij het toevoegen van de binding zijn deze velden belangrijk:</p><table tabindex="0"><thead><tr><th>Veld</th><th>Waarde</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>Selecteer de bucket die je hebt gemaakt</td></tr></tbody></table><p>De variabelenaam moet exact <code>img_r2</code> zijn. Uploaden, lezen en verwijderen van R2-bestanden hangen allemaal van deze bindingnaam af.</p><h3 id="_3-deploy-het-project-opnieuw" tabindex="-1">3. Deploy het project opnieuw <a class="header-anchor" href="#_3-deploy-het-project-opnieuw" aria-label="Permalink to &quot;3. Deploy het project opnieuw&quot;">​</a></h3><p>Sla de binding op en deploy ImgBed daarna opnieuw, zodat de Worker- of Pages-runtime toegang krijgt tot <code>img_r2</code>.</p><h2 id="wat-je-in-imgbed-ziet" tabindex="-1">Wat je in ImgBed ziet <a class="header-anchor" href="#wat-je-in-imgbed-ziet" aria-label="Permalink to &quot;Wat je in ImgBed ziet&quot;">​</a></h2><p>Zodra de R2-binding beschikbaar is, open je:</p><ol><li>Systeeminstellingen.</li><li>Uploadinstellingen.</li><li>Het kanaal <code>Cloudflare R2</code>.</li></ol><p>Het systeem maakt automatisch een vast kanaal aan:</p><table tabindex="0"><thead><tr><th>Veld</th><th>Vaste waarde</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td><code>Cloudflare R2</code></td></tr><tr><td>Kanaaltype</td><td><code>cfr2</code></td></tr><tr><td>Opslagmodus</td><td><code>binding</code></td></tr><tr><td>Configuratiebron</td><td>Omgevingsbinding</td></tr></tbody></table><p>Dit is een vast bindingkanaal. Je hoeft niet op Kanaal toevoegen te klikken om het aan te maken, en je kunt het niet verwijderen zoals een normaal kanaal.</p><h2 id="bewerkbare-velden-in-het-beheer" tabindex="-1">Bewerkbare velden in het beheer <a class="header-anchor" href="#bewerkbare-velden-in-het-beheer" aria-label="Permalink to &quot;Bewerkbare velden in het beheer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Veld</th><th>Functie</th><th>Verplicht</th></tr></thead><tbody><tr><td>Kanaal inschakelen</td><td>Bepaalt of R2 meedoet bij de uploadselectie.</td><td>Ja</td></tr><tr><td>Account ID</td><td>Alleen nodig als quotalimieten actief zijn en officieel R2-gebruik moet worden opgevraagd.</td><td>Aanbevolen bij quotalimieten</td></tr><tr><td>Bucketnaam</td><td>Alleen nodig als quotalimieten actief zijn en officieel R2-gebruik moet worden opgevraagd.</td><td>Aanbevolen bij quotalimieten</td></tr><tr><td>Quotalimiet</td><td>Bepaalt of dit R2-kanaal op basis van capaciteit wordt meegenomen bij uploads.</td><td>Nee</td></tr><tr><td>Drempel</td><td>Stopt schrijven naar dit kanaal zodra het opgegeven percentage is bereikt.</td><td>Verplicht bij quotalimieten</td></tr></tbody></table><p>De Account ID vind je in het accountinformatiepaneel van het Cloudflare Dashboard. Vul deze alleen in als ImgBed R2-quota moet opvragen en afdwingen.</p><p><img src="'+t+'" alt="Account ID ophalen" loading="lazy"></p><h2 id="stappen" tabindex="-1">Stappen <a class="header-anchor" href="#stappen" aria-label="Permalink to &quot;Stappen&quot;">​</a></h2><ol><li>Maak een R2-bucket in Cloudflare.</li><li>Open de Cloudflare-instellingen van het ImgBed-project.</li><li>Voeg een R2-bucketbinding toe.</li><li>Zet <code>Variable name</code> op <code>img_r2</code>.</li><li>Selecteer de R2-bucket die je hebt gemaakt.</li><li>Sla de binding op en deploy ImgBed opnieuw.</li><li>Ga terug naar ImgBed -&gt; Systeeminstellingen -&gt; Uploadinstellingen.</li><li>Controleer of het kanaal <code>Cloudflare R2</code> verschijnt en ingeschakeld is.</li></ol><p>Wil je R2 laten meedoen aan uploadselectie op basis van capaciteit, schakel dan de quotalimiet in en vul Account ID, bucketnaam, quotalimiet en drempel in voordat je opslaat.</p><p><img src="'+n+'" alt="Quotalimieten instellen" loading="lazy"></p><h2 id="controleren" tabindex="-1">Controleren <a class="header-anchor" href="#controleren" aria-label="Permalink to &quot;Controleren&quot;">​</a></h2><ul><li>Het vaste kanaal <code>Cloudflare R2</code> verschijnt in Uploadinstellingen.</li><li>De kanaalkaart laat zien dat het kanaal actief is.</li><li>Een klein testbestand uploadt succesvol en de teruggegeven link opent normaal.</li><li>Als bij het openen van een bestand <code>R2 database binding is not configured</code> verschijnt, heeft de runtime de binding <code>img_r2</code> niet ontvangen. Controleer de bindingnaam in Cloudflare en deploy het project opnieuw.</li></ul>',37)])])}const f=i(r,[["render",c]]);export{k as __pageData,f as default};
